    21→@Command({
    22→	name: 'reindex-products-neural',
    23→	description: 'Sync styles_mv products to OpenSearch neural search index',
    24→})
    25→export class ReindexProductsNeuralCommand extends CommandRunner {
    26→	private readonly logger = new Logger(ReindexProductsNeuralCommand.name);
    27→	private isShuttingDown = false;
    28→	private currentOperation: Promise<void> | null = null;
    29→	private isCancelled = false;
    30→
    31→	constructor(
    32→		private readonly opensearchNeuralService: OpensearchNeuralService,
    33→		private readonly stylesMvModel: StylesMvModel,
    34→		private readonly configService: EnvConfigService,
    35→	) {
    36→		super();
    37→		this.setupGracefulShutdown();
    38→	}
    39→
    40→	@CronJobExecution({ jobName: 'reindex-products-neural' })
    41→	async run(
    42→		_passedParams: string[],
    43→		options: ReindexProductsNeuralOptions,
    44→	): Promise<void> {
    45→		if (this.isShuttingDown) {
    46→			this.logger.warn('Command cancelled due to shutdown signal');
    47→			return;
    48→		}
    49→
    50→		const batchSize = options.batchSize ?? 150;
    51→		const concurrency = options.concurrency ?? 5;
    52→		const createIndex = options.createIndex ?? false;
    53→
    54→		try {
    55→			const indexName = this.configService.get<string>({ key: OPENSEARCH_INDEX_NAME });
    56→
    57→			if (createIndex) {
    58→				this.logger.log(`Creating OpenSearch index: ${indexName}`);
    59→				await this.opensearchNeuralService.createProductsIndex({ indexName });
    60→			}
    61→
    62→			this.logger.log('Starting to reindex products to OpenSearch');
    63→			this.logger.log(`Batch size: ${batchSize}, Concurrency: ${concurrency}`);
    64→
    65→			const totalCount = await this.stylesMvModel.count();
    66→			this.logger.log(`Total products to index: ${totalCount}`);
    67→
    68→			if (totalCount === 0) {
    69→				this.logger.warn('No products found to index');
    70→				return;
    71→			}
    72→
    73→			const totalBatches = Math.ceil(totalCount / batchSize);
    74→			const batches = Array.from({ length: totalBatches }, (_, i) => ({
    75→				offset: i * batchSize,
    76→				limit: batchSize,
    77→			}));
    78→
    79→			const progressBar = new ProgressBar({ total: totalCount });
    80→			let totalIndexed = 0;
    81→			let totalErrors = 0;
    82→
    83→			this.currentOperation = this.processBatches({
    84→				batches,
    85→				concurrency,
    86→				indexName,
    87→				progressBar,
    88→				onBatchComplete: (indexed, errors) => {
    89→					totalIndexed += indexed;
    90→					totalErrors += errors;
    91→				},
    92→			});
    93→
    94→			await this.currentOperation;
    95→
    96→			if (!this.isCancelled) {
    97→				progressBar.finish();
    98→				this.logger.log('Successfully completed reindexing products to OpenSearch');
    99→				this.logger.log(
   100→					`Total indexed: ${totalIndexed}, Total errors: ${totalErrors}, Total processed: ${totalIndexed + totalErrors}`,
   101→				);
   102→			} else {
   103→				this.logger.warn('Reindexing was cancelled');
   104→			}
   105→		} catch (error) {
   106→			if (this.isShuttingDown || this.isCancelled) {
   107→				this.logger.warn('Command interrupted during shutdown');
   108→				return;
   109→			}
