   117→	private async processBatches({
   118→		batches,
   119→		concurrency,
   120→		indexName,
   121→		progressBar,
   122→		onBatchComplete,
   123→	}: {
   124→		batches: { offset: number; limit: number }[];
   125→		concurrency: number;
   126→		indexName: string;
   127→		progressBar: ProgressBar;
   128→		onBatchComplete: (indexed: number, errors: number) => void;
   129→	}): Promise<void> {
   130→		await runWithConcurrencyLimit({
   131→			items: batches,
   132→			concurrency,
   133→			handler: async (batch) => {
   134→				if (this.isCancelled) {
   135→					return { indexed: 0, errors: 0 };
   136→				}
   137→
   138→				const styles = await this.stylesMvModel.findAll({
   139→					limit: batch.limit,
   140→					offset: batch.offset,
   141→				});
   142→
   143→				if (styles.length === 0) {
   144→					return { indexed: 0, errors: 0 };
   145→				}
   146→
   147→				const result = await this.opensearchNeuralService.bulkIndexProducts({
   148→					indexName,
   149→					styles,
   150→				});
   151→
   152→				return result;
   153→			},
   154→			onItemComplete: (result) => {
   155→				progressBar.increment(result.indexed + result.errors);
   156→				onBatchComplete(result.indexed, result.errors);
   157→			},
   158→			onItemError: (error) => {
   159→				this.logger.error(`Batch processing error: ${(error as Error).message}`);
   160→			},
   161→		});
   162→	}
