   164→	@Option({
   165→		flags: '-b, --batch-size <batchSize>',
   166→		description: 'Number of products per batch (default: 150)',
   167→	})
   168→	parseBatchSize(value: string): number {
   169→		const size = parseInt(value, 10);
   170→		if (isNaN(size) || size < 1 || size > 1000) {
   171→			throw new Error('Batch size must be between 1 and 1000');
   172→		}
   173→		return size;
