   196→	private setupGracefulShutdown(): void {
   197→		const signals: NodeJS.Signals[] = ['SIGTERM', 'SIGINT', 'SIGHUP', 'SIGQUIT'];
   198→
   199→		signals.forEach((signal) => {
   200→			process.on(signal, () => {
   201→				void this.handleShutdown(signal);
   202→			});
   203→		});
   204→
   205→		process.on('uncaughtException', (error) => {
   206→			this.logger.error(`Uncaught exception: ${error.message}`);
   207→			void this.handleShutdown('SIGTERM');
   208→		});
   209→
   210→		process.on('unhandledRejection', (reason) => {
   211→			this.logger.error(`Unhandled rejection: ${String(reason)}`);
   212→			void this.handleShutdown('SIGTERM');
   213→		});
   214→	}
   215→
   216→	private async handleShutdown(signal: string): Promise<void> {
   217→		if (this.isShuttingDown) {
   218→			this.logger.warn('Force shutdown requested, exiting immediately');
   219→			process.exit(1);
   220→		}
   221→
   222→		this.logger.warn(`Received ${signal} signal, initiating graceful shutdown...`);
   223→		this.isShuttingDown = true;
   224→		this.isCancelled = true;
   225→
   226→		try {
   227→			if (this.currentOperation) {
   228→				this.logger.log('Waiting for current operation to complete...');
   229→
   230→				const shutdownTimeout = setTimeout(() => {
   231→					this.logger.error('Graceful shutdown timeout, forcing exit');
   232→					process.exit(1);
   233→				}, 30000);
   234→
   235→				await this.currentOperation;
   236→				clearTimeout(shutdownTimeout);
   237→			}
   238→
   239→			this.logger.log('Graceful shutdown completed');
   240→			process.exit(0);
   241→		} catch (error) {
   242→			this.logger.error(`Error during shutdown: ${(error as Error).message}`);
   243→			process.exit(1);
   244→		}
   245→	}
   246→}
